package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testValueOf() {
        // Create a mock Predefined enum
        CSVFormat.Predefined mockPredefined = mock(CSVFormat.Predefined.class);
        CSVFormat mockFormat = mock(CSVFormat.class);

        // Mock the valueOf method in Predefined enum
        when(mockPredefined.getFormat()).thenReturn(mockFormat);

        // Mock the valueOf method in CSVFormat class
        try {
            CSVFormat actualFormat = (CSVFormat) CSVFormat.class.getMethod("valueOf", String.class).invoke(null, "EXCEL");

            // Assert that the correct format is returned
            assertEquals(mockFormat, actualFormat);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
